};

export const SYSTEM_INSTRUCTIONS = {
  MEDICAL: "You are Nova, an intelligent medical assistant. Provide helpful, accurate, and cautious medical information. Always clarify that you are an AI and not a replacement for a professional doctor. In emergencies, direct users to call emergency services.",
  TRIAGE: "You are a rapid triage assistant. Provide extremely concise, immediate guidance based on symptoms. Keep responses under 50 words.",
  RESEARCH: "You are a deep medical researcher. Use your thinking capabilities to analyze complex medical queries thoroughly before answering."
};

export function base64ToUint8Array(base64: string): Uint8Array {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

export function arrayBufferToBase64(buffer: ArrayBuffer): string {
  let binary = '';
  const bytes = new Uint8Array(buffer);
  const len = bytes.byteLength;
  for (let i = 0; i < len; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
}

export async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number = 24000,
  numChannels: number = 1
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

export function createPcmBlob(data: Float32Array): { data: string; mimeType: string } {
  const l = data.length;
  const int16 = new Int16Array(l);
  for (let i = 0; i < l; i++) {
    int16[i] = data[i] * 32768;
  }
  const uint8 = new Uint8Array(int16.buffer);
  return {
    data: arrayBufferToBase64(uint8.buffer),
    mimeType: 'audio/pcm;rate=16000',
  };
}

import { GoogleGenAI, Modality, Type, LiveSession } from "@google/genai";
import { MODELS, SYSTEM_INSTRUCTIONS } from '../constants';

// We must create a new instance when needed to ensure fresh API key usage
const getAI = () => new GoogleGenAI({ apiKey: process.env.API_KEY });

export const GeminiService = {
  // 1. Fast Triage (Lite model)
  async quickTriage(symptoms: string) {
    const ai = getAI();
    const response = await ai.models.generateContent({
      model: MODELS.FAST,
      contents: symptoms,
      config: {
        systemInstruction: SYSTEM_INSTRUCTIONS.TRIAGE,
      }
    });
    return response.text;
  },

  // 2. Chatbot (Pro model)
  async chat(message: string, history: any[] = []) {
    const ai = getAI();
    // history conversion would happen here in a real app
    const response = await ai.models.generateContent({
      model: MODELS.CHAT,
      contents: message,
      config: {
        systemInstruction: SYSTEM_INSTRUCTIONS.MEDICAL,
      }
    });
    return response.text;
  },

  // 3. Image Analysis (Pro Vision)
  async analyzeImage(base64Image: string, prompt: string) {
    const ai = getAI();
    const response = await ai.models.generateContent({
      model: MODELS.VISION,
      contents: {
        parts: [
          { inlineData: { mimeType: 'image/jpeg', data: base64Image } },
          { text: prompt }
        ]
      }
    });
    return response.text;
  },

  // 4. Video Analysis (Pro Vision)
  async analyzeVideo(base64Video: string, prompt: string, mimeType: string) {
    const ai = getAI();
    const response = await ai.models.generateContent({
      model: MODELS.VIDEO,
      contents: {
        parts: [
          { inlineData: { mimeType: mimeType, data: base64Video } },
          { text: prompt }
        ]
      }
    });
    return response.text;
  },

  // 5. Google Maps (Flash 2.5)
  async findNearby(query: string, location: { lat: number; lng: number }) {
    const ai = getAI();
    const response = await ai.models.generateContent({
      model: MODELS.MAPS,
      contents: query,
      config: {
        tools: [{ googleMaps: {} }],
        toolConfig: {
          retrievalConfig: {
            latLng: {
              latitude: location.lat,
              longitude: location.lng
            }
          }
        }
      }
    });
    return {
      text: response.text,
      chunks: response.candidates?.[0]?.groundingMetadata?.groundingChunks
    };
  },

  // 6. Search Grounding (Flash 3)
  async research(query: string) {
    const ai = getAI();
    const response = await ai.models.generateContent({
      model: MODELS.SEARCH,
      contents: query,
      config: {
        tools: [{ googleSearch: {} }]
      }
    });
    return {
      text: response.text,
      chunks: response.candidates?.[0]?.groundingMetadata?.groundingChunks
    };
  },

  // 7. Thinking Mode (Pro 3)
  async thinkDeep(query: string) {
    const ai = getAI();
    const response = await ai.models.generateContent({
      model: MODELS.THINKING,
      contents: query,
      config: {
        thinkingConfig: { thinkingBudget: 32768 },
        systemInstruction: SYSTEM_INSTRUCTIONS.RESEARCH
      }
    });
    return response.text;
  },

  // 8. Image Generation (Pro 3 Image)
  async generateAnatomyImage(prompt: string, aspectRatio: string) {
    const ai = getAI();
    const response = await ai.models.generateContent({
      model: MODELS.IMAGE_GEN,
      contents: { parts: [{ text: prompt }] },
      config: {
        imageConfig: {
          aspectRatio: aspectRatio as any, // Cast to any to avoid strict enum type issues if string passed
          imageSize: '1K'
        }
      }
    });

    // Extract image
    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) {
        return `data:image/png;base64,${part.inlineData.data}`;
      }
    }
    return null;
  },

  // 9. Transcription (Flash 3)
  async transcribeAudio(base64Audio: string) {
    const ai = getAI();
    const response = await ai.models.generateContent({
      model: MODELS.TRANSCRIPTION,
      contents: {
        parts: [
          { inlineData: { mimeType: 'audio/mp3', data: base64Audio } }, // Assuming mp3/wav common format
          { text: "Transcribe this medical note accurately." }
        ]
      }
    });
    return response.text;
  },

  // 10. TTS (Flash 2.5 TTS)
  async generateSpeech(text: string) {
    const ai = getAI();
    const response = await ai.models.generateContent({
      model: MODELS.TTS,
      contents: { parts: [{ text }] },
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: { voiceName: 'Fenrir' } // Deep, calm voice
          }
        }
      }
    });

    const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    return base64Audio;
  },

  // 11. Live Connect
  async connectLive(callbacks: any) {
    const ai = getAI();
    return ai.live.connect({
      model: MODELS.LIVE,
      callbacks,
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Kore' }}
        },
        systemInstruction: SYSTEM_INSTRUCTIONS.MEDICAL + " You are speaking in a voice consultation."
      }
    });
  }
};

