import React, { useEffect, useRef, useState } from 'react';
import { GeminiService } from '../services/gemini';
import { createPcmBlob, decodeAudioData } from '../utils/audio';

export const LiveConsultation: React.FC = () => {
  const [connected, setConnected] = useState(false);
  const [isSpeaking, setIsSpeaking] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const sessionRef = useRef<any>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const streamRef = useRef<MediaStream | null>(null);
  const nextStartTimeRef = useRef<number>(0);

  const startSession = async () => {
    try {
      setError(null);
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      streamRef.current = stream;

      const audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      audioContextRef.current = audioCtx;

      const inputSource = audioCtx.createMediaStreamSource(stream);
      const processor = audioCtx.createScriptProcessor(4096, 1, 1);

      const outputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });

      // Initialize Gemini Live Session
      const sessionPromise = GeminiService.connectLive({
        onopen: () => {
          setConnected(true);
          // Audio Processing Loop
          processor.onaudioprocess = (e) => {
            const inputData = e.inputBuffer.getChannelData(0);
            const pcmBlob = createPcmBlob(inputData);
            sessionPromise.then(session => {
              session.sendRealtimeInput({ media: pcmBlob });
            });
          };
          inputSource.connect(processor);
          processor.connect(audioCtx.destination);
        },
        onmessage: async (message: any) => {
          // Handle Audio Output
          const audioData = message.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
          if (audioData) {
            setIsSpeaking(true);
            const buffer = await decodeAudioData(
                new Uint8Array(atob(audioData).split('').map(c => c.charCodeAt(0))),
                outputCtx
            );

            const source = outputCtx.createBufferSource();
            source.buffer = buffer;
            source.connect(outputCtx.destination);

            const currentTime = outputCtx.currentTime;
            const startTime = Math.max(nextStartTimeRef.current, currentTime);
            source.start(startTime);
            nextStartTimeRef.current = startTime + buffer.duration;

            source.onended = () => {
                if (outputCtx.currentTime >= nextStartTimeRef.current) {
                    setIsSpeaking(false);
                }
            }
          }
        },
        onclose: () => {
          setConnected(false);
          cleanup();
        },
        onerror: (err: any) => {
          console.error(err);
          setError("Connection lost or failed.");
          setConnected(false);
          cleanup();
        }
      });

      sessionRef.current = sessionPromise;

    } catch (err) {
      console.error(err);
      setError("Failed to access microphone or connect to Gemini.");
    }
  };

  const cleanup = () => {
    if (streamRef.current) {
      streamRef.current.getTracks().forEach(track => track.stop());
    }
    if (audioContextRef.current) {
      audioContextRef.current.close();
    }
    if (sessionRef.current) {
        sessionRef.current.then((s: any) => s.close());
    }
    setConnected(false);
    setIsSpeaking(false);
  };

  useEffect(() => {
    return cleanup;
  }, []);

  return (
    <div className="h-full flex flex-col items-center justify-center p-8 bg-slate-50">
      <div className="w-full max-w-2xl bg-white rounded-2xl shadow-xl overflow-hidden border border-slate-200">
        <div className="p-8 text-center space-y-6">
          <div className="relative mx-auto w-32 h-32 flex items-center justify-center">
            {connected && (
              <span className={`absolute inset-0 rounded-full bg-primary-500 opacity-20 ${isSpeaking ? 'animate-ping' : ''}`}></span>
            )}
            <div className={`relative w-24 h-24 rounded-full flex items-center justify-center transition-colors ${connected ? 'bg-primary-600' : 'bg-slate-200'}`}>
              <span className="material-symbols-outlined text-4xl text-white">
                {connected ? 'graphic_eq' : 'mic_off'}
              </span>
            </div>
          </div>

          <div>
            <h2 className="text-2xl font-bold text-slate-800">
              {connected ? 'Live Consultation Active' : 'Start Live Consultation'}
            </h2>
            <p className="text-slate-500 mt-2">
              {connected 
                ? 'Listening... Speak naturally to Nova.' 
                : 'Click below to begin a real-time voice session with the AI doctor.'}
            </p>
          </div>

          {error && (
            <div className="text-red-500 text-sm bg-red-50 p-2 rounded">
              {error}
            </div>
          )}

          <button
            onClick={connected ? cleanup : startSession}
            className={`px-8 py-3 rounded-full font-semibold transition-all ${
              connected 
                ? 'bg-red-500 hover:bg-red-600 text-white' 
                : 'bg-primary-600 hover:bg-primary-700 text-white shadow-lg hover:shadow-xl'
            }`}
          >
            {connected ? 'End Session' : 'Start Session'}
          </button>
        </div>

        <div className="bg-slate-50 p-4 text-xs text-center text-slate-400 border-t border-slate-100">
          Powered by Gemini 2.5 Native Audio • Low Latency Mode
        </div>
      </div>
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { GeminiService } from '../services/gemini';
import { ChatMessage } from '../types';

export const SymptomChat: React.FC = () => {
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const endRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => endRef.current?.scrollIntoView({ behavior: 'smooth' });
  useEffect(scrollToBottom, [messages]);

  const handleSend = async () => {
    if (!input.trim() || loading) return;

    const userMsg: ChatMessage = {
      id: Date.now().toString(),
      role: 'user',
      text: input,
      timestamp: new Date()
    };

    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setLoading(true);

    try {
      const response = await GeminiService.chat(userMsg.text, messages);
      const aiMsg: ChatMessage = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: response || "I couldn't generate a response.",
        timestamp: new Date()
      };
      setMessages(prev => [...prev, aiMsg]);
    } catch (e) {
      setMessages(prev => [...prev, {
        id: Date.now().toString(),
        role: 'model',
        text: "I'm having trouble connecting right now. Please try again.",
        timestamp: new Date(),
        isError: true
      }]);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="flex flex-col h-full bg-slate-50">
      <div className="flex-1 overflow-y-auto p-4 space-y-4">
        {messages.length === 0 && (
          <div className="h-full flex items-center justify-center text-slate-400">
            <div className="text-center">
              <span className="material-symbols-outlined text-4xl mb-2">chat_bubble_outline</span>
              <p>Start a conversation about your symptoms.</p>
            </div>
          </div>
        )}
        {messages.map((msg) => (
          <div key={msg.id} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[80%] rounded-2xl px-4 py-3 ${
              msg.role === 'user' 
                ? 'bg-primary-600 text-white rounded-br-none' 
                : msg.isError 
                  ? 'bg-red-100 text-red-800' 
