export const HealthcareLocator: React.FC = () => {
  const [query, setQuery] = useState('');
  const [results, setResults] = useState<{ text: string; chunks: any[] } | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleSearch = () => {
    if (!query.trim()) return;
    setLoading(true);
    setError(null);
    setResults(null);

    if (!navigator.geolocation) {
      setError("Geolocation is not supported by your browser");
      setLoading(false);
      return;
    }

    navigator.geolocation.getCurrentPosition(
      async (position) => {
        try {
          const location = {
            lat: position.coords.latitude,
            lng: position.coords.longitude
          };
          const data = await GeminiService.findNearby(query, location);
          setResults(data);
        } catch (e) {
          setError("Failed to fetch location data.");
        } finally {
          setLoading(false);
        }
      },
      () => {
        setError("Location access denied. Please enable location services.");
        setLoading(false);
      }
    );
  };

  return (
    <div className="p-8 h-full overflow-y-auto">
      <div className="max-w-4xl mx-auto space-y-6">
        <div className="bg-white p-8 rounded-xl shadow-sm border border-slate-200">
          <h2 className="text-2xl font-bold text-slate-800 mb-4">Find Healthcare Nearby</h2>
          <p className="text-slate-500 mb-6">Powered by Google Maps Grounding. Find specialists, hospitals, and clinics near you.</p>

          <div className="flex gap-4">
            <input
              type="text"
              value={query}
              onChange={(e) => setQuery(e.target.value)}
              placeholder="e.g., '24 hour pharmacy' or 'cardiologist'"
              className="flex-1 border border-slate-300 rounded-lg px-4 py-3 focus:ring-2 focus:ring-green-500 outline-none"
              onKeyDown={(e) => e.key === 'Enter' && handleSearch()}
            />
            <button
              onClick={handleSearch}
              disabled={loading}
              className="bg-green-600 hover:bg-green-700 text-white px-8 py-3 rounded-lg font-medium transition-colors disabled:opacity-50"
            >
              {loading ? 'Searching...' : 'Search'}
            </button>
          </div>
          {error && <p className="text-red-500 mt-3 text-sm">{error}</p>}
        </div>

        {results && (
          <div className="grid grid-cols-1 gap-6">
             <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
                <h3 className="font-semibold text-slate-800 mb-4">AI Recommendation</h3>
                <p className="text-slate-700 whitespace-pre-wrap">{results.text}</p>
             </div>

             {results.chunks && results.chunks.length > 0 && (
               <div className="space-y-4">
                 <h3 className="font-semibold text-slate-500 uppercase text-xs tracking-wider">Found Locations</h3>
                 {results.chunks.map((chunk, idx) => {
                   const place = chunk.web?.uri ? chunk.web : chunk.maps; // Fallback or maps specific
                   // Maps grounding usually returns structure in specific map format, we try to extract common fields
                   // Note: The specific structure for maps grounding can vary, relying on WebChunk structure for generic display
                   if (!place) return null;

                   return (
                     <a 
                       key={idx} 
                       href={place.uri} 
                       target="_blank" 
                       rel="noopener noreferrer"
                       className="block bg-white p-4 rounded-lg border border-slate-200 hover:border-green-400 hover:shadow-md transition-all group"
                     >
                       <div className="flex justify-between items-start">
                         <div>
                            <h4 className="font-medium text-slate-900 group-hover:text-green-600">{place.title}</h4>
                            <p className="text-sm text-slate-500 mt-1 truncate max-w-xl">{place.uri}</p>
                         </div>
                         <span className="material-symbols-outlined text-slate-400 group-hover:text-green-500">open_in_new</span>
                       </div>
                     </a>
                   );
                 })}
               </div>
             )}
