import React, { useState, useRef } from 'react';
import { GeminiService } from '../services/gemini';
import { arrayBufferToBase64, decodeAudioData } from '../utils/audio';

export const VoiceRecords: React.FC = () => {
  const [mode, setMode] = useState<'transcribe' | 'tts'>('transcribe');
  const [text, setText] = useState('');
  const [loading, setLoading] = useState(false);
  const [isRecording, setIsRecording] = useState(false);

  // TTS
  const [audioUrl, setAudioUrl] = useState<string | null>(null);

  // Recorder
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const chunksRef = useRef<Blob[]>([]);

  const toggleRecording = async () => {
    if (isRecording) {
      mediaRecorderRef.current?.stop();
      setIsRecording(false);
    } else {
      try {
        const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
        const mr = new MediaRecorder(stream);
        mediaRecorderRef.current = mr;
        chunksRef.current = [];

        mr.ondataavailable = (e) => chunksRef.current.push(e.data);
        mr.onstop = async () => {
          setLoading(true);
          const blob = new Blob(chunksRef.current, { type: 'audio/mp3' }); // usually webm/ogg but we hint mp3 to gemini
          const buffer = await blob.arrayBuffer();
          const base64 = arrayBufferToBase64(buffer);

          try {
            const result = await GeminiService.transcribeAudio(base64);
            setText(result || "Transcription empty.");
          } catch (e) {
            setText("Error transcribing audio.");
          } finally {
            setLoading(false);
            stream.getTracks().forEach(t => t.stop());
          }
        };
        mr.start();
        setIsRecording(true);
      } catch (e) {
        alert("Microphone access denied.");
      }
    }
  };

  const handleTTS = async () => {
    if (!text.trim()) return;
    setLoading(true);
    setAudioUrl(null);
    try {
      const base64 = await GeminiService.generateSpeech(text);
      if (base64) {
        // Convert to blob URL for playback
        const binary = atob(base64);
        const array = new Uint8Array(binary.length);
        for(let i=0; i<binary.length; i++) array[i] = binary.charCodeAt(i);
        const blob = new Blob([array], { type: 'audio/wav' }); // PCM usually wrapped or raw, but browser can play if formatted. 
        // Actually the API returns raw PCM often, or WAV. Let's assume the API returns usable audio data (the system prompt implies decoding PCM manually for Live, but TTS endpoint returns audio data).
        // The system prompt TTS example decodes manually. Let's try simple Blob first, if not we assume PCM.
        // Wait, system prompt says: "The audio bytes returned by the API is raw PCM data." for Live API.
        // For TTS: "The audio bytes returned by the API is raw PCM data."
        // So we must decode it like Live API to play it.

        const audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
        const audioBuffer = await decodeAudioData(array, audioCtx, 24000);

        // Simple playback
        const source = audioCtx.createBufferSource();
        source.buffer = audioBuffer;
        source.connect(audioCtx.destination);
        source.start();
      }
    } catch (e) {
      console.error(e);
      alert("TTS Failed.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="p-8 h-full overflow-y-auto">
      <div className="max-w-4xl mx-auto space-y-6">
        <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
          <div className="flex border-b border-slate-100">
            <button 
              onClick={() => setMode('transcribe')}
              className={`flex-1 py-4 font-medium transition-colors ${mode === 'transcribe' ? 'bg-slate-50 text-slate-800 border-b-2 border-slate-800' : 'text-slate-500'}`}
            >
              Dictation (Speech to Text)
            </button>
            <button 
              onClick={() => setMode('tts')}
              className={`flex-1 py-4 font-medium transition-colors ${mode === 'tts' ? 'bg-slate-50 text-slate-800 border-b-2 border-slate-800' : 'text-slate-500'}`}
            >
              Read Aloud (Text to Speech)
            </button>
          </div>

          <div className="p-8">
            {mode === 'transcribe' ? (
              <div className="text-center space-y-6">
                <div className={`w-24 h-24 mx-auto rounded-full flex items-center justify-center cursor-pointer transition-all ${isRecording ? 'bg-red-500 animate-pulse' : 'bg-slate-100 hover:bg-slate-200'}`} onClick={toggleRecording}>
                  <span className={`material-symbols-outlined text-4xl ${isRecording ? 'text-white' : 'text-slate-600'}`}>
                    {isRecording ? 'stop' : 'mic'}
                  </span>
                </div>
                <p className="text-slate-500">
                  {isRecording ? 'Recording... Tap to stop.' : 'Tap mic to start dictating patient notes.'}
                </p>
                {loading && <p className="text-sm text-blue-500">Transcribing...</p>}
                {text && (
                  <div className="mt-6 text-left p-6 bg-slate-50 rounded-xl border border-slate-200">
                    <p className="whitespace-pre-wrap text-slate-800">{text}</p>
                  </div>
                )}
              </div>
            ) : (
              <div className="space-y-4">
                <textarea
                  value={text}
                  onChange={(e) => setText(e.target.value)}
                  placeholder="Enter text to convert to speech..."
                  className="w-full h-40 border border-slate-300 rounded-lg p-4 focus:ring-2 focus:ring-slate-500 outline-none resize-none"
                />
                <button
                  onClick={handleTTS}
                  disabled={loading || !text.trim()}
                  className="bg-slate-800 hover:bg-slate-900 text-white px-6 py-2 rounded-lg font-medium"
                >
                  {loading ? 'Generating Audio...' : 'Read Aloud'}
                </button>
                <p className="text-xs text-slate-400 mt-2">Note: Audio plays immediately upon generation.</p>
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

