const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<View>(View.DASHBOARD);
  const [apiKeyReady, setApiKeyReady] = useState(false);

  useEffect(() => {
    const checkKey = async () => {
      // Check if window.aistudio exists (it might not in standard dev, but prompt assumes it for key selection context)
      if ((window as any).aistudio) {
        const hasKey = await (window as any).aistudio.hasSelectedApiKey();
        if (hasKey) {
          setApiKeyReady(true);
        }
      } else {
        // Fallback for environments where the wrapper isn't present, assume env var is enough
        setApiKeyReady(true);
      }
    };
    checkKey();
  }, []);

  const handleSelectKey = async () => {
    if ((window as any).aistudio) {
        await (window as any).aistudio.openSelectKey();
        setApiKeyReady(true);
    }
  };

  if (!apiKeyReady) {
    return (
      <div className="h-screen w-screen flex flex-col items-center justify-center bg-slate-50 space-y-6">
