    switch (currentView) {
      case View.DASHBOARD: return <Dashboard onViewChange={setCurrentView} />;
      case View.LIVE_CONSULT: return <LiveConsultation />;
      case View.SYMPTOM_CHAT: return <SymptomChat />;
