import React, { useState, useEffect, useCallback } from 'react';
import { GeminiService } from '../services/gemini';

export const HealthcareLocator: React.FC = () => {
  const [query, setQuery] = useState('Open hospitals, pharmacies, and medical stores nearby');
  const [results, setResults] = useState<{ text: string; chunks: any[] } | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [status, setStatus] = useState('Initializing...');

  const performSearch = useCallback(async (searchQuery: string) => {
    setLoading(true);
    setError(null);
    setStatus('Acquiring your location...');

    if (!navigator.geolocation) {
      setError("Geolocation is not supported by your browser");
      setLoading(false);
      return;
    }

    navigator.geolocation.getCurrentPosition(
      async (position) => {
        try {
          const location = {
            lat: position.coords.latitude,
            lng: position.coords.longitude
          };

          setStatus('Scanning for nearby facilities...');
          const data = await GeminiService.findNearby(searchQuery, location);
          setResults(data);
        } catch (e) {
          setError("Failed to connect to Nova services.");
        } finally {
          setLoading(false);
          setStatus('');
        }
      },
      (err) => {
        let msg = "Location access denied.";
        if (err.code === 1) msg = "Please allow location access to find nearby hospitals.";
        else if (err.code === 2) msg = "Location unavailable. Please check your GPS.";
        else if (err.code === 3) msg = "Location request timed out.";
        setError(msg);
        setLoading(false);
      },
      {
        enableHighAccuracy: true,
        timeout: 10000,
        maximumAge: 0
      }
    );
  }, []);

  // Auto-search on mount
  useEffect(() => {
    performSearch(query);
  }, []); // Run once on mount

  const handleManualSearch = () => {
    if (!query.trim()) return;
    performSearch(query);
  };

  return (
    <div className="p-8 h-full overflow-y-auto">
      <div className="max-w-4xl mx-auto space-y-6">
        <div className="bg-white p-8 rounded-xl shadow-sm border border-slate-200">
          <div className="flex items-center space-x-3 mb-4">
             <div className="w-10 h-10 bg-emerald-100 text-emerald-600 rounded-lg flex items-center justify-center">
                <span className="material-symbols-outlined">add_location_alt</span>
             </div>
             <div>
                <h2 className="text-2xl font-bold text-slate-800">Care Locator</h2>
                <p className="text-slate-500 text-sm">Automatically finding open care centers near you.</p>
             </div>
          </div>

          <div className="flex gap-4">
            <input
              type="text"
              value={query}
              onChange={(e) => setQuery(e.target.value)}
              placeholder="e.g., '24 hour pharmacy' or 'cardiologist'"
              className="flex-1 border border-slate-300 rounded-lg px-4 py-3 focus:ring-2 focus:ring-emerald-500 outline-none transition-all"
              onKeyDown={(e) => e.key === 'Enter' && handleManualSearch()}
            />
            <button
              onClick={handleManualSearch}
              disabled={loading}
              className="bg-emerald-600 hover:bg-emerald-700 text-white px-8 py-3 rounded-lg font-medium transition-colors disabled:opacity-50 flex items-center gap-2"
            >
              {loading ? (
                  <>
                    <span className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin"></span>
                    <span>Locating...</span>
                  </>
              ) : (
                  <>
                    <span className="material-symbols-outlined">search</span>
                    <span>Search</span>
                  </>
              )}
            </button>
          </div>

          {status && loading && (
            <div className="mt-4 flex items-center text-emerald-600 text-sm animate-pulse">
                <span className="material-symbols-outlined text-base mr-2">my_location</span>
                {status}
            </div>
          )}

          {error && (
            <div className="mt-4 p-4 bg-red-50 text-red-700 rounded-lg border border-red-100 flex items-center gap-2">
                <span className="material-symbols-outlined">location_disabled</span>
                {error}
                <button onClick={() => performSearch(query)} className="ml-auto text-sm underline hover:text-red-900">Retry</button>
            </div>
          )}
        </div>

        {results && (
          <div className="grid grid-cols-1 gap-6 animate-fade-in">
             <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
                <div className="flex items-center gap-2 mb-4">
                    <span className="material-symbols-outlined text-emerald-600">ai_stars</span>
                    <h3 className="font-semibold text-slate-800">Nova Recommendation</h3>
                </div>
                <div className="text-slate-700 whitespace-pre-wrap leading-relaxed">
                    {results.text}
                </div>
             </div>

             {results.chunks && results.chunks.length > 0 && (
               <div className="space-y-4">
                 <div className="flex items-center justify-between">
                    <h3 className="font-semibold text-slate-500 uppercase text-xs tracking-wider">Nearby Facilities</h3>
                    <span className="text-xs text-slate-400 bg-slate-100 px-2 py-1 rounded">Verified by Google Maps</span>
                 </div>

                 <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                 {results.chunks.map((chunk, idx) => {
                   const place = chunk.web?.uri ? chunk.web : chunk.maps;
                   if (!place) return null;

                   // Attempt to extract more details if available in the raw chunk, 
                   // though typically title and URI are the standard guaranteed fields.
                   return (
                     <a 
                       key={idx} 
                       href={place.uri} 
                       target="_blank" 
                       rel="noopener noreferrer"
                       className="block bg-white p-5 rounded-xl border border-slate-200 hover:border-emerald-400 hover:shadow-lg hover:-translate-y-1 transition-all group relative overflow-hidden"
                     >
                       <div className="absolute top-0 right-0 p-4 opacity-10 group-hover:opacity-20 transition-opacity">
                            <span className="material-symbols-outlined text-4xl text-emerald-600">storefront</span>
                       </div>

                       <div className="flex justify-between items-start relative z-10">
                         <div>
                            <h4 className="font-bold text-slate-900 group-hover:text-emerald-700 text-lg mb-1">{place.title}</h4>
                            <div className="flex items-center text-xs text-emerald-600 font-medium mb-2">
                                <span className="w-2 h-2 bg-emerald-500 rounded-full mr-2 animate-pulse"></span>
                                Open Now (Verify hours)
                            </div>
                            <p className="text-xs text-slate-400 truncate max-w-[200px]">{place.uri}</p>
                         </div>
                       </div>

                       <div className="mt-4 pt-4 border-t border-slate-100 flex justify-between items-center">
                            <span className="text-xs font-semibold text-slate-500 group-hover:text-emerald-600 transition-colors">View on Maps</span>
                            <span className="material-symbols-outlined text-slate-300 group-hover:text-emerald-500 group-hover:translate-x-1 transition-all text-sm">arrow_forward</span>
                       </div>
                     </a>
                   );
                 })}
                 </div>
               </div>
             )}
          </div>
        )}
      </div>
    </div>
  );
};

