import { GoogleGenAI, Modality, Type, LiveSession } from "@google/genai";
import { MODELS, SYSTEM_INSTRUCTIONS } from '../constants';

// We must create a new instance when needed to ensure fresh API key usage
const getAI = () => new GoogleGenAI({ apiKey: process.env.API_KEY });

export const GeminiService = {
  // 1. Fast Triage (Lite model)
  async quickTriage(symptoms: string) {
    const ai = getAI();
    const response = await ai.models.generateContent({
      model: MODELS.FAST,
      contents: symptoms,
      config: {
        systemInstruction: SYSTEM_INSTRUCTIONS.TRIAGE,
      }
    });
    return response.text;
  },

  // 2. Chatbot (Pro model) - Updated for Multimodal
  async chat(message: string, images: string[] = [], history: any[] = []) {
    const ai = getAI();
    let contents: any = message;

    if (images && images.length > 0) {
        const parts: any[] = [{ text: message }];
        images.forEach(img => {
            // Expecting data:image/xyz;base64,DATA
            const [meta, data] = img.split(',');
            const mimeType = meta.split(':')[1].split(';')[0];
            parts.push({
                inlineData: {
                    mimeType,
                    data
                }
            });
        });
        contents = { parts };
    }

    const response = await ai.models.generateContent({
      model: MODELS.CHAT,
      contents: contents,
      config: {
        systemInstruction: SYSTEM_INSTRUCTIONS.MEDICAL,
      }
    });
    return response.text;
  },

  // 3. Image Analysis (Pro Vision)
  async analyzeImage(base64Image: string, prompt: string) {
    const ai = getAI();
    const response = await ai.models.generateContent({
      model: MODELS.VISION,
      contents: {
        parts: [
          { inlineData: { mimeType: 'image/jpeg', data: base64Image } },
          { text: prompt }
        ]
      }
    });
    return response.text;
  },

  // 4. Video Analysis (Pro Vision)
  async analyzeVideo(base64Video: string, prompt: string, mimeType: string) {
    const ai = getAI();
    const response = await ai.models.generateContent({
      model: MODELS.VIDEO,
      contents: {
        parts: [
          { inlineData: { mimeType: mimeType, data: base64Video } },
          { text: prompt }
        ]
      }
    });
    return response.text;
  },

  // 5. Google Maps (Flash 2.5)
  async findNearby(query: string, location: { lat: number; lng: number }) {
    const ai = getAI();
    const response = await ai.models.generateContent({
      model: MODELS.MAPS,
      contents: query,
      config: {
        tools: [{ googleMaps: {} }],
        toolConfig: {
          retrievalConfig: {
            latLng: {
              latitude: location.lat,
              longitude: location.lng
            }
          }
        }
      }
    });
    return {
      text: response.text,
      chunks: response.candidates?.[0]?.groundingMetadata?.groundingChunks
    };
  },

  // 6. Search Grounding (Flash 3)
  async research(query: string) {
    const ai = getAI();
    const response = await ai.models.generateContent({
      model: MODELS.SEARCH,
      contents: query,
      config: {
        tools: [{ googleSearch: {} }]
      }
    });
    return {
      text: response.text,
      chunks: response.candidates?.[0]?.groundingMetadata?.groundingChunks
    };
  },

  // 7. Thinking Mode (Pro 3)
  async thinkDeep(query: string) {
    const ai = getAI();
    const response = await ai.models.generateContent({
      model: MODELS.THINKING,
      contents: query,
      config: {
        thinkingConfig: { thinkingBudget: 32768 },
        systemInstruction: SYSTEM_INSTRUCTIONS.RESEARCH
      }
    });
    return response.text;
  },

  // 8. Image Generation (Pro 3 Image)
  async generateAnatomyImage(prompt: string, aspectRatio: string) {
    const ai = getAI();
    const response = await ai.models.generateContent({
      model: MODELS.IMAGE_GEN,
      contents: { parts: [{ text: prompt }] },
      config: {
        imageConfig: {
          aspectRatio: aspectRatio as any, // Cast to any to avoid strict enum type issues if string passed
          imageSize: '1K'
        }
      }
    });

    // Extract image
    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) {
        return `data:image/png;base64,${part.inlineData.data}`;
      }
    }
    return null;
  },

  // 9. Transcription (Flash 3)
  async transcribeAudio(base64Audio: string) {
    const ai = getAI();
    const response = await ai.models.generateContent({
      model: MODELS.TRANSCRIPTION,
      contents: {
        parts: [
          { inlineData: { mimeType: 'audio/mp3', data: base64Audio } }, // Assuming mp3/wav common format
          { text: "Transcribe this medical note accurately." }
        ]
      }
    });
    return response.text;
  },

  // 10. TTS (Flash 2.5 TTS)
  async generateSpeech(text: string) {
    const ai = getAI();
    const response = await ai.models.generateContent({
      model: MODELS.TTS,
      contents: { parts: [{ text }] },
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: { voiceName: 'Fenrir' } // Deep, calm voice
          }
        }
      }
    });

    const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    return base64Audio;
  },

  // 11. Live Connect
  async connectLive(callbacks: any) {
    const ai = getAI();
    return ai.live.connect({
      model: MODELS.LIVE,
      callbacks,
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Kore' }}
        },
        systemInstruction: SYSTEM_INSTRUCTIONS.MEDICAL + " You are speaking in a voice consultation."
      }
    });
  }
};

import React, { useState, useRef, useEffect } from 'react';
import { GeminiService } from '../services/gemini';
import { ChatMessage } from '../types';

export const SymptomChat: React.FC = () => {
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [input, setInput] = useState('');
  const [selectedImages, setSelectedImages] = useState<string[]>([]);
  const [loading, setLoading] = useState(false);
  const endRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const scrollToBottom = () => endRef.current?.scrollIntoView({ behavior: 'smooth' });
  useEffect(scrollToBottom, [messages, selectedImages]);

  const handleImageSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files) {
      const files = Array.from(e.target.files);
      files.forEach(file => {
        const reader = new FileReader();
        reader.onload = (ev) => {
          if (ev.target?.result) {
            setSelectedImages(prev => [...prev, ev.target!.result as string]);
          }
        };
        reader.readAsDataURL(file);
      });
    }
  };

  const removeImage = (index: number) => {
    setSelectedImages(prev => prev.filter((_, i) => i !== index));
  };

  const handleSend = async () => {
    if ((!input.trim() && selectedImages.length === 0) || loading) return;

    const currentImages = [...selectedImages];
    const userMsg: ChatMessage = {
      id: Date.now().toString(),
      role: 'user',
      text: input,
      images: currentImages.length > 0 ? currentImages : undefined,
      timestamp: new Date()
    };

    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setSelectedImages([]);
    setLoading(true);

    try {
      const response = await GeminiService.chat(userMsg.text, currentImages, messages);
      const aiMsg: ChatMessage = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: response || "I couldn't generate a response.",
        timestamp: new Date()
      };
      setMessages(prev => [...prev, aiMsg]);
    } catch (e) {
      setMessages(prev => [...prev, {
        id: Date.now().toString(),
        role: 'model',
        text: "I'm having trouble connecting right now. Please try again.",
        timestamp: new Date(),
        isError: true
      }]);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="flex flex-col h-full bg-slate-50">
      <div className="flex-1 overflow-y-auto p-4 space-y-4">
        {messages.length === 0 && (
          <div className="h-full flex items-center justify-center text-slate-400">
            <div className="text-center">
              <span className="material-symbols-outlined text-4xl mb-2">chat_bubble_outline</span>
              <p>Start a conversation about your symptoms.</p>
              <p className="text-xs mt-2 text-slate-300">You can upload images for analysis.</p>
            </div>
          </div>
        )}
        {messages.map((msg) => (
          <div key={msg.id} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[80%] rounded-2xl px-4 py-3 ${
              msg.role === 'user' 
                ? 'bg-primary-600 text-white rounded-br-none' 
                : msg.isError 
                  ? 'bg-red-100 text-red-800' 
                  : 'bg-white text-slate-800 border border-slate-200 rounded-bl-none shadow-sm'
            }`}>
              {msg.images && msg.images.length > 0 && (
                <div className="flex flex-wrap gap-2 mb-2">
                  {msg.images.map((img, i) => (
                    <img key={i} src={img} alt="Attachment" className="w-32 h-32 object-cover rounded-lg border border-white/20" />
                  ))}
                </div>
              )}
              <p className="whitespace-pre-wrap text-sm">{msg.text}</p>
              <span className="text-[10px] opacity-70 block mt-1 text-right">
                {msg.timestamp.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
              </span>
            </div>
          </div>
        ))}
        {loading && (
          <div className="flex justify-start">
             <div className="bg-white px-4 py-3 rounded-2xl rounded-bl-none border border-slate-200 shadow-sm flex space-x-1">
                <div className="w-2 h-2 bg-slate-400 rounded-full animate-bounce"></div>
                <div className="w-2 h-2 bg-slate-400 rounded-full animate-bounce" style={{animationDelay: '0.2s'}}></div>
                <div className="w-2 h-2 bg-slate-400 rounded-full animate-bounce" style={{animationDelay: '0.4s'}}></div>
             </div>
          </div>
        )}
        <div ref={endRef} />
      </div>

      <div className="p-4 bg-white border-t border-slate-200">
        {/* Image Previews */}
        {selectedImages.length > 0 && (
          <div className="flex gap-3 mb-3 overflow-x-auto pb-2">
            {selectedImages.map((img, idx) => (
              <div key={idx} className="relative flex-shrink-0">
                <img src={img} alt="Preview" className="h-16 w-16 object-cover rounded-lg border border-slate-200" />
                <button 
                  onClick={() => removeImage(idx)}
                  className="absolute -top-1 -right-1 bg-red-500 text-white rounded-full w-5 h-5 flex items-center justify-center text-xs hover:bg-red-600"
                >
                  <span className="material-symbols-outlined text-[14px]">close</span>
                </button>
              </div>
            ))}
          </div>
        )}

        <div className="flex space-x-2 items-end">
          <input 
            type="file" 
            ref={fileInputRef}
            className="hidden" 
            accept="image/*" 
            multiple 
            onChange={handleImageSelect}
          />
          <button
            onClick={() => fileInputRef.current?.click()}
            className="p-3 text-slate-400 hover:text-primary-600 hover:bg-slate-50 rounded-lg transition-colors"
            title="Attach images"
          >
            <span className="material-symbols-outlined">attach_file</span>
          </button>

          <textarea
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => {
                if (e.key === 'Enter' && !e.shiftKey) {
                    e.preventDefault();
                    handleSend();
                }
            }}
            placeholder="Describe your symptoms..."
            className="flex-1 border border-slate-300 rounded-xl px-4 py-3 focus:ring-2 focus:ring-primary-500 outline-none text-sm resize-none max-h-32 min-h-[46px]"
            rows={1}
          />
          <button
            onClick={handleSend}
            disabled={loading || (!input.trim() && selectedImages.length === 0)}
            className="bg-primary-600 hover:bg-primary-700 text-white p-3 rounded-xl font-medium transition-colors disabled:opacity-50 flex items-center justify-center"
          >
            <span className="material-symbols-outlined">send</span>
          </button>
        </div>
      </div>
    </div>
  );
};

