const QUICK_FILTERS = [
  { id: 'pharmacy', label: 'Medical Stores', icon: 'medication', query: 'medical stores and pharmacies' },
  { id: 'hospital', label: 'Hospitals', icon: 'local_hospital', query: 'hospitals and emergency centers' },
