import React, { useState, useRef, useEffect } from 'react';
import { GeminiService } from '../services/gemini';
import { ChatMessage } from '../types';

export const SymptomChat: React.FC = () => {
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [input, setInput] = useState('');
  const [selectedImages, setSelectedImages] = useState<string[]>([]);
  const [loading, setLoading] = useState(false);

  // Camera State
  const [isCameraOpen, setIsCameraOpen] = useState(false);
  const videoRef = useRef<HTMLVideoElement>(null);
  const streamRef = useRef<MediaStream | null>(null);

  const endRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const scrollToBottom = () => endRef.current?.scrollIntoView({ behavior: 'smooth' });
  useEffect(scrollToBottom, [messages, selectedImages]);

  // Clean up camera on unmount
  useEffect(() => {
    return () => {
      if (streamRef.current) {
        streamRef.current.getTracks().forEach(track => track.stop());
      }
    };
  }, []);

  const handleImageSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files) {
      for (let i = 0; i < e.target.files.length; i++) {
        const file = e.target.files[i];
        const reader = new FileReader();
        reader.onload = (ev) => {
          if (ev.target?.result) {
            setSelectedImages(prev => [...prev, ev.target!.result as string]);
          }
        };
        reader.readAsDataURL(file);
      }
    }
  };

  const removeImage = (index: number) => {
    setSelectedImages(prev => prev.filter((_, i) => i !== index));
  };

  // Camera Functions
  const startCamera = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ 
        video: { facingMode: 'environment' } 
      });
      streamRef.current = stream;
      setIsCameraOpen(true);
      // Wait for render cycle to attach stream
      setTimeout(() => {
        if (videoRef.current) {
          videoRef.current.srcObject = stream;
          videoRef.current.play();
        }
      }, 100);
    } catch (err) {
      console.error("Camera Error:", err);
      alert("Could not access camera. Please check permissions.");
    }
  };

  const stopCamera = () => {
    if (streamRef.current) {
      streamRef.current.getTracks().forEach(track => track.stop());
      streamRef.current = null;
    }
    setIsCameraOpen(false);
  };

  const capturePhoto = () => {
    if (videoRef.current) {
      const video = videoRef.current;
      const canvas = document.createElement('canvas');
      canvas.width = video.videoWidth;
      canvas.height = video.videoHeight;
      const ctx = canvas.getContext('2d');
      if (ctx) {
        ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
        const dataUrl = canvas.toDataURL('image/jpeg', 0.8);
        setSelectedImages(prev => [...prev, dataUrl]);
        stopCamera();
      }
    }
  };

  const analyzeMessageSentiment = async (msgId: string, text: string) => {
    try {
      const sentiment = await GeminiService.analyzeSentiment(text);
      setMessages(prev => prev.map(m => m.id === msgId ? { ...m, sentiment } : m));
    } catch (e) {
      console.error("Sentiment analysis failed", e);
    }
  };

  const handleSend = async () => {
    if ((!input.trim() && selectedImages.length === 0) || loading) return;

    const currentImages = [...selectedImages];
    const userMsg: ChatMessage = {
      id: Date.now().toString(),
      role: 'user',
      text: input,
      images: currentImages.length > 0 ? currentImages : undefined,
      timestamp: new Date()
    };

    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setSelectedImages([]);
    setLoading(true);

    // Analyze User Sentiment in background
    if (userMsg.text) {
        analyzeMessageSentiment(userMsg.id, userMsg.text);
    }

    try {
      const response = await GeminiService.chat(userMsg.text, currentImages, messages);
      const aiMsg: ChatMessage = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: response || "I couldn't generate a response.",
        timestamp: new Date()
      };
      setMessages(prev => [...prev, aiMsg]);

      // Analyze Model Sentiment
      analyzeMessageSentiment(aiMsg.id, aiMsg.text);

    } catch (e) {
      setMessages(prev => [...prev, {
        id: Date.now().toString(),
        role: 'model',
        text: "I'm having trouble connecting right now. Please try again.",
        timestamp: new Date(),
        isError: true
      }]);
    } finally {
      setLoading(false);
    }
  };

  const getSentimentColor = (sentiment?: string) => {
    switch(sentiment) {
        case 'positive': return 'bg-emerald-400 shadow-emerald-200';
        case 'negative': return 'bg-rose-500 shadow-rose-200';
        case 'neutral': return 'bg-slate-400 shadow-slate-200';
        default: return 'bg-transparent';
    }
  };

  return (
    <div className="flex flex-col h-full bg-slate-50 relative">

      {/* Camera Modal */}
      {isCameraOpen && (
        <div className="absolute inset-0 z-50 bg-black/90 flex flex-col items-center justify-center p-4 backdrop-blur-sm">
          <div className="relative w-full max-w-lg bg-black rounded-2xl overflow-hidden shadow-2xl border border-slate-800">
            <video 
              ref={videoRef} 
              className="w-full h-auto object-cover" 
              autoPlay 
              playsInline 
              muted
            />

            <div className="absolute bottom-6 left-0 right-0 flex items-center justify-center gap-8">
               <button 
                 onClick={stopCamera}
                 className="p-4 rounded-full bg-slate-800/80 text-white hover:bg-slate-700 transition-colors backdrop-blur-md"
               >
                 <span className="material-symbols-outlined text-2xl">close</span>
               </button>

               <button 
                 onClick={capturePhoto}
                 className="p-1 rounded-full border-4 border-white/30 hover:border-white/60 transition-all"
               >
                 <div className="w-16 h-16 bg-white rounded-full hover:scale-95 transition-transform"></div>
               </button>

               <div className="w-14"></div> {/* Spacer for balance */}
            </div>
          </div>
        </div>
      )}

      <div className="flex-1 overflow-y-auto p-4 space-y-4">
        {messages.length === 0 && (
          <div className="h-full flex items-center justify-center text-slate-400">
            <div className="text-center">
              <span className="material-symbols-outlined text-4xl mb-2">chat_bubble_outline</span>
              <p>Start a conversation about your symptoms.</p>
              <p className="text-xs mt-2 text-slate-300">You can upload images or take photos for analysis.</p>
            </div>
          </div>
        )}
        {messages.map((msg) => (
          <div key={msg.id} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`relative max-w-[80%] rounded-2xl px-4 py-3 ${
              msg.role === 'user' 
                ? 'bg-primary-600 text-white rounded-br-none' 
                : msg.isError 
                  ? 'bg-red-100 text-red-800' 
                  : 'bg-white text-slate-800 border border-slate-200 rounded-bl-none shadow-sm'
            }`}>
              {msg.images && msg.images.length > 0 && (
                <div className="flex flex-wrap gap-2 mb-2">
                  {msg.images.map((img, i) => (
                    <img key={i} src={img} alt="Attachment" className="w-32 h-32 object-cover rounded-lg border border-white/20" />
                  ))}
                </div>
              )}
              <p className="whitespace-pre-wrap text-sm">{msg.text}</p>

              <div className="flex items-center justify-end gap-2 mt-1">
                  {/* Sentiment Dot */}
                  {msg.sentiment && (
                    <div 
                        className={`w-2 h-2 rounded-full shadow-[0_0_8px] ${getSentimentColor(msg.sentiment)}`}
                        title={`Sentiment: ${msg.sentiment}`}
                    ></div>
                  )}
                  <span className="text-[10px] opacity-70">
                    {msg.timestamp.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                  </span>
              </div>
            </div>
          </div>
        ))}
        {loading && (
          <div className="flex justify-start">
             <div className="bg-white px-4 py-3 rounded-2xl rounded-bl-none border border-slate-200 shadow-sm flex space-x-1">
                <div className="w-2 h-2 bg-slate-400 rounded-full animate-bounce"></div>
                <div className="w-2 h-2 bg-slate-400 rounded-full animate-bounce" style={{animationDelay: '0.2s'}}></div>
                <div className="w-2 h-2 bg-slate-400 rounded-full animate-bounce" style={{animationDelay: '0.4s'}}></div>
             </div>
          </div>
        )}
        <div ref={endRef} />
      </div>

      <div className="p-4 bg-white border-t border-slate-200">
        <div className="flex space-x-2 items-end">
          <input 
            type="file" 
            ref={fileInputRef}
            className="hidden" 
            accept="image/*" 
            multiple 
            onChange={handleImageSelect}
          />

          {/* Attachment Button */}
          <button
            onClick={() => fileInputRef.current?.click()}
            className="p-3 text-slate-400 hover:text-primary-600 hover:bg-slate-50 rounded-lg transition-colors"
            title="Attach images"
          >
            <span className="material-symbols-outlined">attach_file</span>
          </button>

          {/* Camera Button */}
          <button
            onClick={startCamera}
            className="p-3 text-slate-400 hover:text-primary-600 hover:bg-slate-50 rounded-lg transition-colors"
            title="Take Photo"
          >
            <span className="material-symbols-outlined">photo_camera</span>
          </button>

          <textarea
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => {
                if (e.key === 'Enter' && !e.shiftKey) {
                    e.preventDefault();
                    handleSend();
                }
            }}
            placeholder="Describe your symptoms..."
            className="flex-1 border border-slate-300 rounded-xl px-4 py-3 focus:ring-2 focus:ring-primary-500 outline-none text-sm resize-none max-h-32 min-h-[46px]"
            rows={1}
          />
          <button
            onClick={handleSend}
            disabled={loading || (!input.trim() && selectedImages.length === 0)}
            className="bg-primary-600 hover:bg-primary-700 text-white w-12 h-12 rounded-xl font-medium transition-colors disabled:opacity-50 flex items-center justify-center shadow-md flex-shrink-0"
          >
            {loading ? (
                <span className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin"></span>
            ) : (
                <span className="material-symbols-outlined">send</span>
            )}
          </button>
        </div>

        {/* Image Previews */}
        {selectedImages.length > 0 && (
          <div className="flex gap-3 mt-3 overflow-x-auto pb-2">
            {selectedImages.map((img, idx) => (
              <div key={idx} className="relative flex-shrink-0 group">
                <img src={img} alt="Preview" className="h-20 w-20 object-cover rounded-lg border border-slate-200 shadow-sm" />
                <button 
                  onClick={() => removeImage(idx)}
                  className="absolute -top-2 -right-2 bg-red-500 text-white rounded-full w-6 h-6 flex items-center justify-center text-xs hover:bg-red-600 shadow-md transition-transform transform hover:scale-110"
                >
                  <span className="material-symbols-outlined text-[14px]">close</span>
                </button>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { GeminiService } from '../services/gemini';

export const AnatomyStudio: React.FC = () => {
  const [prompt, setPrompt] = useState('');
  const [aspectRatio, setAspectRatio] = useState('1:1');
  const [image, setImage] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);

  // Zoom and Pan State
  const [zoom, setZoom] = useState(1);
  const [pan, setPan] = useState({ x: 0, y: 0 });
  const [isDragging, setIsDragging] = useState(false);
  const [dragStart, setDragStart] = useState({ x: 0, y: 0 });

  const generate = async () => {
    if (!prompt.trim()) return;
    setLoading(true);
    setImage(null);
    setZoom(1);
    setPan({ x: 0, y: 0 });

    try {
      const imgData = await GeminiService.generateAnatomyImage(prompt, aspectRatio);
      if (imgData) setImage(imgData);
    } catch (e) {
      console.error(e);
      alert('Failed to generate image. Ensure you have selected a Paid API Key.');
    } finally {
      setLoading(false);
    }
  };

  // Pan Handlers
  const handleMouseDown = (e: React.MouseEvent) => {
    if (!image) return;
    e.preventDefault();
    setIsDragging(true);
    setDragStart({ x: e.clientX - pan.x, y: e.clientY - pan.y });
  };

  const handleMouseMove = (e: React.MouseEvent) => {
    if (!isDragging) return;
    e.preventDefault();
    setPan({
      x: e.clientX - dragStart.x,
      y: e.clientY - dragStart.y
    });
  };

  const handleMouseUp = () => {
    setIsDragging(false);
  };

  // Zoom Handlers
  const handleWheel = (e: React.WheelEvent) => {
    if (!image) return;
    // e.preventDefault(); // React synthetic events might not support this depending on attachment, but often fine.
    const scaleAmount = -e.deltaY * 0.001;
    const newZoom = Math.min(Math.max(0.5, zoom + scaleAmount), 5);
    setZoom(newZoom);
  };

  const adjustZoom = (delta: number) => {
    setZoom(prev => Math.min(Math.max(0.5, prev + delta), 5));
  };

  const resetView = () => {
    setZoom(1);
    setPan({ x: 0, y: 0 });
  };

  const ratios = ['1:1', '3:4', '4:3', '16:9', '9:16'];

  return (
    <div className="p-8 h-full overflow-y-auto">
      <div className="max-w-6xl mx-auto flex flex-col lg:flex-row gap-8 h-[calc(100vh-8rem)]">
        {/* Left Panel: Controls */}
        <div className="w-full lg:w-1/3 space-y-6 flex-shrink-0">
          <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
            <h2 className="text-xl font-bold text-slate-800 mb-4">Anatomy Studio</h2>
            <p className="text-slate-500 text-sm mb-6">Generate detailed medical illustrations for patient education.</p>

            <div className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-2">Description</label>
                <textarea
                  value={prompt}
                  onChange={(e) => setPrompt(e.target.value)}
                  placeholder="e.g., Detailed cross-section of the human heart, showing valves and chambers..."
                  className="w-full border border-slate-300 rounded-lg p-3 h-32 focus:ring-2 focus:ring-pink-500 outline-none resize-none text-sm"
                />
              </div>

              <div>
                <label className="block text-sm font-medium text-slate-700 mb-2">Aspect Ratio</label>
                <div className="grid grid-cols-3 gap-2">
                  {ratios.map(r => (
                    <button
                      key={r}
                      onClick={() => setAspectRatio(r)}
                      className={`py-2 px-3 rounded-lg text-xs font-medium border transition-all ${aspectRatio === r ? 'bg-pink-50 border-pink-500 text-pink-700' : 'border-slate-200 text-slate-600 hover:bg-slate-50'}`}
                    >
                      {r}
                    </button>
                  ))}
                </div>
              </div>

              <button
                onClick={generate}
                disabled={loading}
                className="w-full bg-pink-600 hover:bg-pink-700 text-white py-3 rounded-lg font-medium transition-colors disabled:opacity-50 mt-4 shadow-md hover:shadow-lg flex items-center justify-center gap-2"
              >
                {loading ? (
                    <>
                        <span className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin"></span>
                        <span>Generating Illustration...</span>
                    </>
                ) : 'Generate 3D Model'}
              </button>
            </div>
          </div>

          <div className="bg-blue-50 p-4 rounded-xl border border-blue-100">
             <div className="flex items-start gap-3">
                <span className="material-symbols-outlined text-blue-600 mt-0.5">info</span>
                <div className="text-sm text-blue-800">
                    <p className="font-semibold mb-1">Interactive Viewer</p>
                    <p className="text-blue-700/80 text-xs">Use your mouse wheel to zoom in/out. Click and drag to pan around the generated image to inspect details.</p>
                </div>
             </div>
          </div>
        </div>

        {/* Right Panel: Viewer */}
        <div className="w-full lg:w-2/3 h-full min-h-[500px] flex flex-col">
          <div 
            className={`
                relative flex-1 bg-slate-100 rounded-xl border border-slate-200 overflow-hidden flex items-center justify-center
                ${image ? (isDragging ? 'cursor-grabbing' : 'cursor-grab') : 'cursor-default'}
            `}
            onMouseDown={handleMouseDown}
            onMouseMove={handleMouseMove}
            onMouseUp={handleMouseUp}
            onMouseLeave={handleMouseUp}
            onWheel={handleWheel}
          >
            {/* Grid Background Pattern for professional look */}
            <div className="absolute inset-0 opacity-[0.03] pointer-events-none" 
                 style={{ backgroundImage: 'radial-gradient(#000 1px, transparent 1px)', backgroundSize: '20px 20px' }}>
            </div>

            {loading ? (
              <div className="text-center z-10">
                 <div className="w-16 h-16 border-4 border-pink-200 border-t-pink-600 rounded-full animate-spin mx-auto mb-4"></div>
                 <p className="text-slate-500 font-medium animate-pulse">Rendering high-fidelity anatomy...</p>
              </div>
            ) : image ? (
              <>
                  <img 
                    src={image} 
                    alt="Generated Anatomy" 
                    draggable={false}
                    style={{ 
                        transform: `translate(${pan.x}px, ${pan.y}px) scale(${zoom})`,
                        transition: isDragging ? 'none' : 'transform 0.1s cubic-bezier(0,0,0.2,1)'
                    }}
                    className="max-w-[90%] max-h-[90%] object-contain shadow-2xl rounded-lg select-none pointer-events-none origin-center" 
                  />

                  {/* Floating Controls */}
                  <div className="absolute bottom-6 left-1/2 -translate-x-1/2 bg-white/90 backdrop-blur-md border border-slate-200 rounded-full shadow-lg px-4 py-2 flex items-center gap-4 z-20">
